mapper.select:
select spsg.id as rowId,csu.account as account,csu.name as name,csu.id as expert
from srm_project_solicit_ethic_audit spsg
left join ct_srm_user csu on csu.id=spsg.ethic_expert
where is_cancel=0

    and spsg.sys_no=#{projectSolicitEthicAuditDto.sysNo}


    and spsg.soli_project_id=#{projectSolicitEthicAuditDto.soliProjectId}


    and spsg.ethic_allot_count=#{projectSolicitEthicAuditDto.ethicAllotCount}

select spsee.id as rowId,spsee.soli_project_id as soliProjectId,sps.title as title,csy.name as yearName,cspt.name as projTypeName, suser.name as subuserName,sps.sub_date as subDate,sdept.name as subDeptName,
spsee.ethic_chk_result as auditStatus,spsee.data_status as dataStatus from srm_project_solicit_ethic_audit spsee left join srm_project_solicit sps on sps.id=spsee.soli_project_id left join ct_srm_project_apply_book_type cspabt on cspabt.code=sps.apply_book_type left join ct_srm_proj_type cspt on cspt.code=sps.proj_type left join ct_srm_year csy on csy.code=sps.year left join ct_srm_dept sdept on sdept.id=sps.sub_dept left join ct_srm_user huser on huser.id=sps.head left join ct_srm_user suser on suser.id=sps.sub_user_id
where is_cancel=0 and sps.is_ethic=1 and spsee.sys_no="P011" and spsee.ethic_expert=#{projectSolicitDto.userId}
and sps.title LIKE CONCAT('%', #{projectSolicitDto.title}, '%')
and sps.year=#{projectSolicitDto.year}
and sps.sub_date >= #{projectSolicitDto.startDate}
and sps.sub_date <= #{projectSolicitDto.endDate}
